import{c as i,Q as e,j as o,m as a}from"./chunks/framework.hhGiamYR.js";const v=JSON.parse('{"title":"出使曼托瓦侯爵","description":"","frontmatter":{},"headers":[],"relativePath":"research/machiavelli/machiavelli/diplomatic/lower/37-出使曼托瓦侯爵.md","filePath":"research/machiavelli/machiavelli/diplomatic/lower/37-出使曼托瓦侯爵.md"}'),c={name:"research/machiavelli/machiavelli/diplomatic/lower/37-出使曼托瓦侯爵.md"};function r(l,p,t,s,m,d){return e(),o("div",null,[...p[0]||(p[0]=[a('<h1 id="出使曼托瓦侯爵" tabindex="-1">出使曼托瓦侯爵 <a class="header-anchor" href="#出使曼托瓦侯爵" aria-label="Permalink to &quot;出使曼托瓦侯爵&quot;">​</a></h1><p>出使曼托瓦侯爵 但这样做的前提是：对国王的提及所表明的，不过是双方在一开始就相互 承认的意图。这一意图就是：此项协定要在国王陛下的同意与善意下得到 签署。这件事的迅速解决对我们来说意义重大，因此，你要对此事加以监 督，使其马上得到确定。但是，如果遇上了任何妨碍达到这一点的困难， 你要马上回到这里。另一方面，假如你顺利地完结了此事，那么,你就要 催促侯爵大人，让他带着全部人马(至少是一部分人马)立即启程，因为 你知道时间对我们来说是多么重要。</p><p>发自佛罗伦萨市政宫，日期如上 马尔切洛亲笔</p><p>十人委员会致曼托瓦侯爵①</p><p>1505年5月4日</p><p>杰出的领主： 今天上午，阁下的使节到了我们这里。我们了解了他此次出使的目 的，为了更确定无疑地并尽快地对此出使进行回访，我们决定派遣我们城 邦的公民和国务秘书尼科洛 · 马基雅维利出使阁下，其任务就是向阁下汇 报这里所发生的情况；我们请求您给予此人完全的信任；再会。</p><p>①英译本未收入，由王永忠依据贝尔泰利编校本译出。 — 编者注</p><p>第三次出使锡耶纳的潘多尔福 · 彼得鲁奇</p><p>1505年7月</p><p>这次去锡耶纳的任务是对付一个为西班牙人效力的佣兵队长巴 尔托洛梅奥 ·德 · 阿尔维阿诺，他试图进攻佛罗伦萨的领土，并为 比萨人提供帮助。与德 · 阿尔维阿诺私下达成约定的潘多尔福 · 彼 得鲁奇向佛罗伦萨人通报了这一动向，目的是为了欺骗他们，并试 图从他们那里获得一些军事上的雇佣合同。不过，佛罗伦萨没有和 他签订合同，因为他对该共和国的欺骗和敌意是众所周知的。随 后，8月17日，巴尔托洛梅奥 · 德 · 阿尔维阿诺在马雷马地区的圣 温琴齐奥的托雷被安东尼奥 · 贾科米尼率领的佛罗伦萨人打败。博 纳科尔西的《事记》记载了这一事件的所有细节。</p><p>训 令</p><p>1505年7月16日议决</p><p>尼科洛： 你要骑马前往锡耶纳，在明天早上的工作时间到达，并立即去会见尊 贵的潘多尔福。我们已经为你开具了给他的证明信。他派来了一位秘密特 使告诉我们，他得知巴尔托洛梅奥 ·德 · 阿尔维阿诺想要马上前往皮翁比 诺。你要表示出我们对他通风报信行为的欣喜之情，并为他给我们的提议 而感谢他，同时还要马上补充说，我们之所以将你派遣到他那里去，目的 是了解一下他认为如何才能防止未来继续产生混乱。在你认为是必要的限 度内，你要针对这一话题多加讨论，以便更为有效地发现真相。你要自行</p><p>政务与外交著作 Legazioni,commissarie,scritti di governo</p><p>第三次出使锡耶纳的潘多尔福·彼得鲁奇 加以斟酌，并以你一贯的审慎处事风格，来处理与这一问题相关联的方方 面面。 发自佛罗伦萨市政宫，日期如上 马尔切洛亲笔</p><p>信件1</p><p>诸位大人钧鉴： 我在今天早上与潘多尔福进行了会谈。他当时才刚刚起床，因为我在 打开城门之前就到达了。当我对他谈到诸位大人给我的训令时，他没有让 我继续解释，而是说道： “让我来告诉你这是怎么回事。伦佐 ·达 ·切里 大人从我的地盘上抢走了大约500头牛。为此，我派科尔内略 ·加兰蒂去 巴尔托洛梅奥 ·德 · 阿尔维阿诺那里，对这宗抢劫案进行申诉。我对加兰 蒂下令说，如果他没有得到满意的补偿，就前往罗马，在那里向教皇陛下 进行申诉。科尔内略收到命令离开了。我相信，在伦佐和牛群的所有者之 间大概能达成某种协议。科尔内略随后给我来信说，巴尔托洛梅奥向他解 释说，他已经无力再承担自己士兵的给养，因此被迫决定在下个周四(也 就是今天早上)解除合约，并迁往坎佩里亚扎营，以等待命运的裁决。我 对此惊诧莫名，深感不满，并立即派信使将此事通知了你们的旗手。我同 时写信要求科尔内略去再次拜见巴尔托洛梅奥大人，并以我的名义建议他 悬崖勒马，因为他的行为若是得不到充足的支持，就纯属疯狂之举，而我 却看不到他有机会获得任何可靠的支持。我还让科尔内略告诉他说，在我 们的地盘上，除非是偷，不然他什么也得不到。对于这封信，我今天肯定 会收到一个答复，因此，你最好是等答复到来后，再写信给诸位大人。此 刻，我只能对你重申我已经写给诸位大人的话，即，我已经准备好了去做 我和我的城邦能做的一切。等我收到答复的信后，就给你送去。”这样的</p><p>马基雅维利全集 Opere complete di Niccolo Machiavelli</p><p>第三次出使锡耶纳的潘多尔福·彼得鲁奇 对潘多尔福来说，这一消息似乎表明他必须去集结兵力。为此，他 已经尽力采取了措施。他写信给科尔内略，让他不要返回，而是去盯住 德 · 阿尔维阿诺的军队，并随时报告其动向。他还给詹保罗 · 巴廖尼去 信，要求后者迅速集结，并带着他的所有人马穿过齐亚内，进入马雷马 地区。他还建议你们把所有的部队派到马雷马地区的坎佩里亚。潘多尔福 还补充说，尽管他自己和所有这些公民都想尽其所能阻止德 · 阿尔维阿诺 的举动，但他们不知道该怎样去做，也不知道他们自己的安全如何才能得 到保证。要知道，他们的行为会使自己卷入一场战争，可他们还没有和你 们签订任何确定的协议。因此，在他看来，你们应该首先和他签署一个协 定。如果他以前对自己的看法表达得不够明确，那么,他现在的观点是， 锡耶纳愿意在如下基础上达成协议，即，首先，把1498年的停战协议再延 长5年。如果里面包含了任何不适应当前形势的条款，或是容易引发争端 的条款，则应将其删去。他还要求加上，在条约有效的5年期限内，锡耶</p><p>政务与外交著作 Legazioni,commissarie,scrittidi governo</p><p>第三次出使锡耶纳的潘多尔福·彼得鲁奇 纳只需要保证有50名重骑兵为佛罗伦萨共和国效力。在这一点上，尽管一 开始谈的是100人，但他认为，就算这个数量减少到了50人，对你们来说 也无关紧要，而因为他们要常年保持武装(甚至在本土亦如是),这就会 造成过分高昂的费用。因此，他们之所以提供这50名重骑兵来为你们效 力，主要目的还是为了展现友谊而不是其他原因。其次，假如诸位大人在 5年内收复了比萨，蒙泰普尔恰诺就可以保持独立，而比萨地盘和那50名 重骑兵都任由你们调遣。然而，如果比萨没有在5年内被收复，则他们就 会像在协议签署之前一样，保留讨要蒙泰普尔恰诺的权利。不过，在协议 被正式废止以前，它的条款还是有效的。 对于他的这些话，我回答说，在我收到的指令里，没有告诉我应该如 何讨论这些问题，但我可以把相关情况写信告知佛罗伦萨。尽管如此，如 果我可以表达自己意见的话，我要说，我看不出这样的协定如何能缓解他 的忧虑。这种谈判会耗费很多时间，而在这期间，巴尔托洛梅奥就已经整 装待发了。对此，潘多尔福认为，尚待审议的条款只有两条，4天之内就 能了结，所以不会因为此事而浪费时间。你们可以把你们的人遣至坎佩里 亚，同时由他把他的人送到马雷马地区，或者尝试一下也许能够最有效地 击垮德 · 阿尔维阿诺的其他方法，即把手下有60名重骑兵的维泰利家族从 他那里夺走。他赌咒发誓说，假如在离了维泰利的情况下，德 · 阿尔维阿 诺居然还能挥军前进，那他甘愿被吊死。除了维泰利家族以外，其他的佣 兵队长也可能会脱离德 · 阿尔维阿诺的指挥。如果上述方法会让诸位大人 破费的话，这钱也是值得花的，因为这乃是一劳永逸地使你们免遭德 · 阿 尔维阿诺侵扰的手段。他这个人总是保持着武装状态，自己没有任何财 产，却让所有拥有财产的人感到害怕，而且，由于他天性残忍无情、胆大 妄为，且意大利又满是靠掠夺他人为生的盗贼，这些盗贼便拥向他这里， 以期分一杯羹。 我回答潘多尔福说，由于他最为了解德 · 阿尔维阿诺，所以他比任何 人都更适宜粉碎后者的计划。因此，他不应坐等其他人去建功立业，而应</p><p>第三次出使锡耶纳的潘多尔福·彼得鲁奇</p><p>该迅速实施那些他不断催促别人去执行的措施。我还提醒他说，我们既不 缺乏军队，也不缺乏善意。当别人接受这些军队和善意，并想用它们来促 进共同利益时，我们总是愿意为其效力的。但如果情况并非如此，且托斯 卡纳要遭受新的劫难的话，我们非常清楚，这些劫难将导致某些人的灭 亡，但另外一些人则会逃过此劫。那些将要灭亡的人，也就是那些最为虚 弱的人。这时，他又开口发言了，并试图用长篇大论来为过去的事情辩 护。最后，他要求我向诸位大人去信说，他希望让我留在这里，直到你们 做出决定并答复他。这样的话，他就可以向我口头通知德 · 阿尔维阿诺的 进程了。不过，他恳请我向诸位大人通报说，假如你们要公开你们的意 图，请不要提及他的名字。他抱怨说，在他派人去你们那里时(正是那次 送去的信息让你们把我派到了这里),那人曾提到了他的名字。 我还应该告诉诸位大人，潘多尔福告诉我，由于他的远见，他已经下 令给维泰利家族写信，敦促其脱离德 · 阿尔维阿诺的阵营。他还说，他能 使巴尔托洛梅奥大人耽搁6到8天，或假装自己愿意给他送钱过去，但除非 他首先同诸位大人达成协定，否则他是不会去做这些事的。他又补充说， 如果两国达成了共识，他们就不会缺少捆住德 · 阿尔维阿诺手脚的方法。 你们应该记得，当他1489年给威尼斯人效力的时候，曾经制服过德 · 阿尔 维阿诺。 到目前为止，我所写下的都是从潘多尔福自己嘴里听到的话。我本可 以记录下我对他的言谈的各种回复，但还是决定将其略过，以免让诸位大 人感到乏味。我也无法断定他是否值得信赖，因为，与诸位大人的判断相 比，我在这里的所见所闻无助于让我对此事做出更好的判断。我只能告诉 你们，你们不用指望从这里获得什么好处了，因为潘多尔福现在根本不怕 德 · 阿尔维阿诺。如果他所说的话都属实，那么,能够驱使他去行动的， 不会是对当前状况的恐惧，而只能是对未来状况的恐惧。 我会见了一个自称对我们共和国很友好的锡耶纳人。他告诉我，你们 绝不能信赖任何潘多尔福所承诺或所说的事情。他非常肯定地说，威尼斯</p><p>人正在这里大撒金钱，并且卷进了这件纠纷之中。圭多 · 奥兰迪几周前同 彼得鲁乔大人一起去了威尼斯，几天前才回来，而后者则留在了那里。这 个圭多在送信时伤了一条腿，是由马车运回来的。他刚回到这里，潘多尔 福就上门去会见了他，随后便立即派科尔内略 ·加兰蒂去给德 · 阿尔维阿 诺送信，催促后者挥兵向前。他还告诉德 · 阿尔维阿诺说，他已经派人前 往锡耶纳边界去迎接后者的人马，并为其提供住处。潘多尔福的计划是打 垮我们的现任旗手，因为后者似乎无意与他建立密切的关系。随后，其他 的人既然有利可图，就会愿意与他达成协议。这个锡耶纳人认为，这里正 在酝酿着巨大的阴谋。他承诺说，当我在这里停留时，他会告诉我许多其 他的事情。此人举止彬彬有礼，看上去也非常睿智，但他对这里的统治者 表现出了极大的敌意，这让我感到不能去信任他。尽管如此，我还是把他 对我说的话写信告诉你们。如果他告诉了我更多的事情，我也会继续通知 你们的。诸位大人想必会利用这些信息，以防止各种伤害。 现在的这位信使是在22点离开的。诸位大人请将费用支付给弗朗切斯 科 ·迪 · 卢齐奥。再会! 1505年7月17日，锡耶纳 仆尼科洛 · 马基雅维利，国务秘书</p><p>信件2</p><p>诸位大人钧鉴： 我昨天给诸位大人写了一封长信。送信的人应该在晚上2点抵达。我 希望你们明天之前会回信允许我返回。今天早上，我在大教堂接见了保 罗 · 迪 · 彼得里 · 迪 · 保罗先生。他从这里被流放的时候，曾经居住在 佛罗伦萨。他一上来便告诉我说，他欠我们城邦一个很大的人情，因为 我们不止一次在他流亡时接纳了他，并保护他不受敌人伤害，而且我们 \u2028第三次出使锡耶纳的潘多尔福·彼得鲁奇</p><p>第三次出使锡耶纳的潘多尔福·彼得鲁奇</p><p>的公民也对他表现出了极大的善意和仁慈。他特别提到了弗朗切斯科 ·瓜 尔泰罗蒂先生。他一开始对我说，他不想谈论公共事务，因为他无法像他 希望的那样对我敞开心扉，但在任何个人或私人的事务上，他都愿意为我 效劳。尽管如此，我还是先拐弯抹角地和他扯了好一阵，然后才谈到当前 的局势。他肯定地对我说，德 · 阿尔维阿诺实际上已经启程前往坎佩里 亚，为他助阵的是孔萨尔沃的步兵，甚至可能还包括目前驻扎在皮翁比诺 的军队。威尼斯人将会为他提供资金，而锡耶纳将会允许他在其领地上打 开一条通道，但不会为他的军队准备供给，也不会用其他方式公开支持 他。但是，当我问到德 · 阿尔维阿诺想在坎佩里亚做些什么时，这位保罗 先生说： “他想拿下那个地方，为比萨人提供更多的活动范围，然后根据 他成功的程度来行动。但他应该记住的是，他以前曾经直抵城门之下，所 以这次不妨故技重施，而不要去理会坎佩里亚了。”他随后补充说，令他 感到非常奇怪的是，我们的城邦竟然不愿与锡耶纳的统治者就蒙泰普尔恰 诺的问题做出某些安排，以便稳住他，哪怕这件事已经被三番五次地提出 过了。在他看来，凭借这样的安排，你们等于是“在七月卖太阳”①给锡 耶纳人，因为一旦你们成为了比萨的主人，则不仅潘多尔福，而且蒙泰普 尔恰诺、锡耶纳和托斯卡纳的剩余地区就全在你们的掌控之下了。我向他 指出，如果协议没有达成，过错也全在他们一方，因为佛罗伦萨始终都愿 意去做一切合理的事情。但在我看来，由于潘多尔福和巴尔托洛梅奥及其 支持者联合了起来，因此，在这个节骨眼上，谈论协议什么的都没有用处 了。他对此马上回答道，我不应该这么说，因为根据他的判断，当前乃是 你们促成协定的最好时机，但是时间已经不多了，因为潘多尔福和其他人 之间的谈判还只不过是在会议上动动嘴而已，而就算潘多尔福欺骗了威尼 斯人，也不会给他带来多大麻烦，哪怕后者已经付了一大笔钱。随后，他 对我暗示说，这笔钱是经由他的手来支付的。同样他又说道，潘多尔福不</p><p>①这是一句意大利俗语，指把本属于每个人的东西向别人兜售。 — — 英译本注</p><p>会介意用同样的方式去欺骗孔萨尔沃，因为在这件事情上，威尼斯人和孔 萨尔沃都在被潘多尔福的建议牵着鼻子走。潘多尔福已经对这两方产生了 如此之大的影响，以至于他们完全地信赖他的情报。他还相信，潘多尔福 会很高兴与你们达成协定，以使自己不会完全丧失从这些举措中获得的利 益。而且，他也害怕自己会像之前的那次一样担起整个责任。因此，对他 来说，与你们达成协定乃是最为安全的事情。 对于这些话，我回答说： 一方面，很难相信这些举措都有多么重要的 意义；另一方面，很难相信潘多尔福能够随心所欲地中止这些举措。因 此，我认为潘多尔福不会签署协议。就算他愿意签署，现在的这些准备工 作也不是为了伤害我们，而是为了警告我们。以我们所处的境况，我们连 最为凶狠的攻击都不必惧怕，更不用说那些虚弱的攻击了。然后，我又把 我们和盟友部队的情况告诉了他。他回答说，你们越是安全，他就越是高 兴。他不知道当前这番周密筹划的举措究竟是来势汹汹，还是虚张声势， 但他所能确定的是，不管其性质如何，这番举措都源自潘多尔福的头脑之 中，并且完全倚仗于他。这时，他又大肆宣扬了潘多尔福的能力，并再次 提到了他在各地获得的巨大声望，还说他曾驭马上千，上下自如。然后， 他在离开我时总结说，在他看来，与潘多尔福达成协定，是对我们最为有 利的事情。 在昨天的信中，我向诸位大人详尽汇报了我和另一位朋友的谈话。因 此，我认为理应把这次谈话也向你们详细汇报。在谈话的开头，两人都表 明了对潘多尔福的不满，但正如你能观察到的，他们的结论却与开头迥 异。我没有提到昨天那个人的名字，以免暴露他。但我把第一个人的名字 告诉了你们，因为在我看来，他的言论不太可能使他陷于危险之中，而诸 位大人如果知道他是谁，或许就能更好地判断该对他的陈述抱多大信任。 我只剩一件事需要汇报了。我在昨天的信里忘了告诉诸位大人，在与潘多 尔福的上一次谈话中，当他告诉我他会尽其所能对抗德 · 阿尔维阿诺时， 我回答说，我是相信他的，因为我知道他已经派人去佛罗伦萨募集步兵 \u2028第三次出使锡耶纳的潘多尔福·彼得鲁奇</p><p>Opere complete di Niccolo Machiavelli</p><p>第三次出使锡耶纳的潘多尔福·彼得鲁奇 了。对此，他回应说，他在佛罗伦萨募兵不是为了这个目的，而是因为他最 近创设的一个警官职务需要招募30个人。我后来发现这个说法是真实的。 在昨天的信写完后，潘多尔福派人通知我说，几天之前，长期为他服 务的理发师科尔托纳的巴斯蒂亚诺去科尔托纳给他妹妹的婚礼帮忙，结果 遭到了拘押，因为当地长官怀疑他卷入了反对该国的阴谋。潘多尔福认 为，真相现在应该已经大白了，所以希望你们给个面子，放了这个人。他 恳请我以他的名义向诸位大人提出这项请求，于是我就这么做了。敬请诸 位大人多多关照，保重再会。</p><p>锡耶纳，1505年7月18日，15点 仆尼科洛 · 马基雅维利，国务秘书</p><p>信件3</p><p>诸位大人钧鉴： 我昨天给诸位大人写了一封信，以使你们可以对其中包含的信息善加 利用。我会以同样的方式继续写信告知我的所见所闻。我今天早上收到诸 位大人的回信后，我立即拜见了潘多尔福，并向他汇报了诸位大人的答 复。对于你们提出的停战或联盟，他说棘手的问题应该被单独放在一边， 还说人的智慧常常不足以与上天的意志为敌，而上天则一直都在把它的计 划隐藏起来。对于维泰利家族和其他的雇佣兵队长，他说那是他自己想出 的主意和计划，因为他认为其他方式无法更有效地压制德 · 阿尔维阿诺的 鲁莽行径。但是，除非先听听他们的意见，否则他不敢说他们会要求什么 样的条件。为此，他已经写信去征求他们的意见，且应该在今天得到他们 的回复。一旦他收到回复，就会马上通知我。他相信他能够赢得他们的支 持，除非他们刚刚同德 · 阿尔维阿诺达成了协定，而他对此还一无所知。</p><p>他还没有去接触其他人，因为他害怕巴尔托洛梅奥会有所察觉。除非他能 首先与你们达成协议，否则他是非常不愿意去冒犯巴尔托洛梅奥的，因 为他不想在没有交上朋友的情况下多树敌人。至于停战的问题，既然他 已经开诚布公，把自己的想法对你们坦率相告，并且愿意赞同一切合理的 条件，那么,如果诸位大人真的想达成协议的话，这就不应该是一件难 事。但是，如果你们并不是真的想要达成协议，则一切事情就都会变得困 难了。如果说现在的问题在于那50个人，这是由于蒙泰普尔恰诺不愿免费 提供这些人，就像他们以前同意提供100重骑兵时那样。这时，他又强调 了这一点，说我们必须寻求达成这样的一项协定，以作为保护托斯卡纳安 宁的真正手段。但是，如果诸位大人坦言说，你们在任何情况下都不会签 订这样的条约，而你们又认为不去挑起新的事端符合公共利益的话，他会 对当前这种悬而未决的状况感到更加满意。在他对他的答复中，我主要是 根据诸位大人在信里的建议，像我开始时就做的那样，坚持说时间太仓促 了。他对此回答说，敲定这样一项协定是几小时内就能办完的事，不需要 花上几天时间。巴尔托洛梅奥可能会在他当前驻扎的地方待上一阵子，因 为他已经写信给詹保罗，说他希望同后者在格拉菲尼亚诺会面磋商。詹保 罗此时一定已经上路了。潘多尔福还说，巴尔托洛梅奥想付给他在塞尔瓦 的人马的钱，恐怕还没有运到。因此，为了防止他在背后捅上一刀，潘多 尔福已经派出波德斯塔前往马雷马地区边境的几个波德斯泰里亚①,把那 里的收割成果带到城镇和其他地方，并做好面粉的供应工作。但他相信， 巴尔托洛梅奥很有可能要被迫等上一阵子，因此，时间还是很充裕的。他 又补充说，他不知道巴尔托洛梅奥想从詹保罗那里获得些什么。 为了不让诸位大人感到厌倦，我就不赘述我对詹保罗的答复了。我只 想报告一下他的总结。总结的内容如下：通过与他达成协定，你们能保护 自己的安全，因为双方可以一起采用一些权宜之计，例如拆散巴尔托洛梅</p><p>① 波 德 斯 泰 里 亚( podesterie) 是意大利 一 个城市控制下的次级行政区域，其行政长官称波德斯塔 (podestà) 。— — 中 译 者 注 \u2028第三次出使锡耶纳的潘多尔福·彼得鲁奇</p><p>Opere complete di Niccolò Machiavelli</p><p>第三次出使锡耶纳的潘多尔福·彼得鲁奇 奥的武装力量。但他又说，假如协定没能达成的话，他就无法公然对巴尔 托洛梅奥表现出敌对的态度。尽管如此，他还是会与后者为敌，并为此而 尽其所能。 现在，诸位大人必须从我所写的内容对巴尔托洛梅奥的真实目的加以 判断，因为再同他面谈必然会收效甚微，甚至一无所获。他承认说，他 不知道巴尔托洛梅奥的这个计划是以什么为基础的，但它可能有非常坚 实的基础。他发誓说，这个国家的军队和属民都不会听从巴尔托洛梅奥 的调遣。他说，他不相信詹保罗会用手下的步兵支援巴尔托洛梅奥，也 不知道维泰利家族是否会用手下人马为巴尔托洛梅奥效力，但如果维泰利 家族决定这么做的话，他会得到消息的，因为他在巴尔托洛梅奥身边安插 了眼线，以向他通报后者的一举一动。正由于此，他才能把这些情况告知 我们。他还告诉我，他已经给罗马去信，以弄清整件事情的基础到底是什 么。一旦他得到了答复，就会马上通知你们。别人对我说，当潘多尔福听 说了枢机主教阿斯卡尼奥的死讯后，他曾一度情绪低落，但他现在又重新 振作了起来，并且充满了希望。人们在这里看不到有什么大的准备工作。 我昨天与安东尼奥 ·达 · 韦纳弗罗大人进行了一番长谈，谈话内容除了这 个协定以外，别无他物。像以往一样，他是潘多尔福的主心骨，有着其他 人无法取代的地位。他认为，为了彼此的安全，我们必须签署这个协议。 在签署完后，摧毁任何支持德 · 阿尔维阿诺的力量就是轻而易举的了。他 所建议首先采取的步骤之一，就是去解除巴尔托洛梅奥的武装力量。但 是，为了达到这一目的，我们必须先敲定协议。诸位大人现在可以参考我 所写下的一切内容，运用你们的至高智慧，来选择最好的对策。 潘多尔福曾数次问我曼托瓦侯爵是否收到了他付的钱。我始终都回答 说，在我离开佛罗伦萨时，那笔钱就快送到他手上了。他今天早上告诉 我，他从伦巴第听到消息说，这份合约将不会被执行，因为侯爵发现这件 事有着重重困难，而且他也没有收到钱。我按照一贯的方式回答了他，但 我觉得应该告诉他，我从诸位大人那里得到了消息，诸位大人已经付过他</p><p>政务与外交著作 Legazioni,commissarie,scritti di governo</p><p>第三次出使锡耶纳的潘多尔福·彼得鲁奇 钱了，但必须对此保密，因为诸位大人要让人们普遍有一种还没付钱的 印象，这样才好增加新税。不过，我不知道这么说是否合适，就没有说 出来。尽管如此，诸位大人还是有充足的时间，去决定是否应该让他得 知此事。 若不是我知道诸位大人急切地想要收到我的来信，我就会等到今晚再 发出此信。那样的话，我或许就能告诉你们潘多尔福从德 · 阿尔维阿诺营 中得来的消息了。不过，为了不使诸位大人焦虑，我就在17点将此信寄出 了。请你们付给弗朗切斯科 ·德尔 · 内罗15个卡利尼。 在一同寄去的信里，我向诸位大人提到了潘多尔福的理发师科尔托纳 的巴斯蒂亚诺。他已经回到了这里，很可能是自己逃出来的。潘多尔福告 诉我说，他担心会有针对此人的财产的官司，所以让我请求诸位大人对此 加以阻止，并承诺说，只要你们想要巴斯蒂亚诺，他就会把他送去。我受 潘多尔福之托向你们提出请求，希望你们给我一个能够回应他的答复。 敬请诸位大人多多关照。 1505年7月19日，17点 我忘了告诉诸位大人，潘多尔福多次向我恳求，让我请你们在涉及他 关于巴尔托洛梅奥 ·德 · 阿尔维阿诺的信息上，不要提他的名字。他必须 否认自己与此的关联，因而希望你们不要声张他与诸位大人的联络。 仆尼科洛 · 马基雅维利，国务秘书</p><p>信件4</p><p>诸位大人钧鉴： 从我昨天的信中，诸位大人应该已经了解了这里的事情。对于从 德 · 阿尔维阿诺那里策反维泰利家族的计划，潘多尔福本来将其视为除掉 德 · 阿尔维阿诺的最好和真正必需的手段，但他现在又说，他只是向我提</p><p>Opere complete di Niccolo Machiavelli</p><p>第三次出使锡耶纳的潘多尔福·彼得鲁奇 出他个人的意见，并不知道维泰利家族会怎么想。因此，他必须等待对他 信件的回复。那封信是他在我到达后写给维泰利家族的。在信中，他以一 种泛泛的口吻试探了他们，询问他们是否有意离开德 · 阿尔维阿诺。在那 之后，巴利阿的主席于昨晚2点找到我说，潘多尔福已经收到了涉及此事 的信件。信件分别来自科尔内略 ·加兰蒂和维泰洛 ·维泰利。尽管信里没 有什么不能推迟到明天再说的内容，但由于他曾经说过，军营那里一有消 息，就要马上让我知道，所以，为了信守这一承诺，他还是来通知我：其 他人告诉他，军队已经到达了塞尔瓦，而巴尔托洛梅奥意欲直抵阿尔维阿 诺。他向前挺进的决心已定，绝对不会更改。在启程之前，他还得先拿到 一笔款项，但不知道这笔钱究竟何时才能够到来。潘多尔福还说，詹利索 和维泰洛 ·维泰利已经准备好了去按他的旨意行事，但他们首先还得给他 们身在卡斯泰洛的叔父朱利奥大人和其他兄弟写信，因为按照其习俗，在 得到相互的同意之前，他们是不会去做任何事情的。他还说道，他从罗马 那里听说，德 · 阿尔维阿诺神父在首先同教皇进行了商议之后，已经动身 去了那不勒斯。在这番交谈之后，主席起身告辞，并请我次日早上去拜见 潘多尔福。于是，我早上便去找到了潘多尔福。他把主席昨晚所说的话重 复了一遍，然后继续说道，军队将会在下周二开拔，并以短途行军的方式 沿这一方向挺进。他相信，他们3天之内就会进入锡耶纳境内。巴尔托洛 梅奥已经给潘多尔福捎来话说，当他进入后者的地盘时，将会发布一道 命令，要求手下在能买到需要的东西时就不去抢掠。他还要求潘多尔福 就以下问题拿定主意：到底是让他作为朋友来路过，还是让他作为敌人 来路过。 至于维泰利家族，潘多尔福告诉我，他从他们那里收到了一封泛泛的 回复，就像他之前给他们去信时的泛泛口气一样。在之前的那封信里，他 向他们询问道，假如他需要他们为自己效力的话，他们是否愿意离开巴尔 托洛梅奥。潘多尔福没有提到佛罗伦萨人或是其他任何人。据他说，尽管 他们把自己完全放在了他的手中，但由于他并不完全了解他们的看法，所</p><p>政务与外交著作 Legazioni,commissarie,seritti di governo</p><p>第三次出使锡耶纳的潘多尔福·彼得鲁奇 以也就不知道该说些什么。不过，为了让我能好歹写点有用的东西，他说 他认为维泰利家族正带领60名重骑兵待在巴尔托洛梅奥大人身边，而一份 用通常的报酬雇佣这60个人1年的合同，大概是能够令他满意的。他将会 让锡耶纳承担1/3的费用。在这之后，他又提出了疑问，说他不知道维泰 利家族是否会愿意在你们的领地上效力。不过，他还是相信，可以通过在 协定中加上如下条款来解决这一困难：如果需要他们专门为你们效劳的 话，就不能强迫他们亲自前来，而是可以由其他军官带领40名士兵来效 力。对你们来说，这是可以采取的最佳方案。但潘多尔福随后又补充说， 出于他已经向我解释过的理由，如果不先与他敲定一项协议，就不可能与 维泰利家族达成协定。这是因为，在确保你们的友谊之前，他不想与巴尔 托洛梅奥为敌。我回答说，诸位大人很高兴他能指出问题，但对他的解决 办法不太满意，因为假如危险像他反复宣称的那样迫在眉睫，并且像他坦 承自己所担心的那样，会像伤害到你们一样伤害到他，那么,在消除这种 危险时，他就应该像你们一样迎难而上。如果说，最好的解决方案是从巴 尔托洛梅奥那里策反维泰利家族，那么,这也应该以比他的建议更简短直 接的方式来执行，而不应该像是在1月讨论5月才生效的合同。在我看来， 虽然他以前的行为使他失去了诸位大人的信任，命运正在给他提供机会， 以使他能够重新获得这份信任。无论他采取什么手段，只要他成功地诱使 维泰利家族离开了德 · 阿尔维阿诺，他就向你们证明了他的善意，从而也 就能够与你们达成协定。只要不至于有损体面，他就能得到他想要的，不 论是一份雇佣合同还是其他任何东西。潘多尔福对此回答说，如果他这样 去做的话，就会马上成为德 · 阿尔维阿诺的敌人，而你们随后也可能会抛 弃他。因此，他只会按照自己提议的方案去行动。但他相信，只要你们愿 意去做的话，时间是很充裕的，因为他不认为巴尔托洛梅奥的行动会像他 自己说的那样迅速。这是由于德 · 阿尔维阿诺神父已经去了那不勒斯。他 的目的很可能是去提取巴尔托洛梅奥希望拿到的那笔钱。潘多尔福又补充 说，他认为教皇曾催促巴尔托洛梅奥尽快行事，以使法国人有机会进入托</p><p>马基雅维利全集 Opere complete di Niccolò Machiavelli</p><p>第三次出使锡耶纳的潘多尔福·彼得鲁奇 斯卡纳并制造混乱。他担心这位教皇有朝一日会成为另一个亚历山大六 世。我告诉他，这是另外一个应该尽快扼杀这一苗头的理由。每当我和他 谈话时，我都会敦促他去想想德 · 阿尔维阿诺这一举动可能产生的正面效 果。我还指出，诸位大人已经准备采取一切方法和使用一切力量，来保卫 你们的国家，并对任何试图伤害它的人施加报复。但我说的一切似乎都没 起什么作用，而且我相信他已经下定了决心。如果我们能够探知此事的真 相，倒也不失为一件好事。 诸位大人会注意到，我提到的所有关于巴尔托洛梅奥的信息，全部都 来自潘多尔福。而每当他告诉我什么事情时，他都恳请我要求诸位大人不 要引用他的话。他还希望与维泰利家族的谈判不要公开。他不打算今天再 给他们写信了，也暂时不打算和他们有什么更深入的交往，因为他希望能从 你们那里获得一些回复，然后以此为基础去和维泰利家族进一步谈判。 再回到我获得的关于德 · 阿尔维阿诺的信息。我认为，诸位大人应尽 量避免依赖这些信息，并且最好是尝试从其他地方获取关于他的信息。你 们可以从博尔戈和科尔托纳打听一下，看看是否有人正在卡斯泰洛或佩鲁 贾招募步兵，以及詹保罗是否已经带领军队穿过了齐亚内，因为虽然潘多 尔福说詹保罗随时可能到来，但我们还没有听说他已经启程。潘多尔福今 天早上告诉我说，与他昨天所说的相反，詹保罗不会前往格拉菲尼亚尼去 会见巴尔托洛梅奥，因为他已经派了佩波先生去阿尔维阿诺找他(据说他 已经到达了那里)。 我还得向诸位大人重新提一句，潘多尔福不停地对我断言说，没有了 维泰利家族，德 · 阿尔维阿诺就会被迫放弃他的计划，因为他离开他们就 寸步难行。他所给出的理由是，维泰利家族的军队十分庞大，而如果他们 决定离开德 · 阿尔维阿诺的话，他们就会转而与他为敌。这种突然的反叛 会使其他部队措手不及，从而产生潘多尔福所预测的结果。诸位大人现在 可以对这些事情形成自己的判断了。 敬请多多关照。</p><p>政务与外交著作 Legazioni,commissarie,scrittidi governo</p><p>第三次出使锡耶纳的潘多尔福·彼得鲁奇 1505年7月20日锡耶纳，15点 请诸位大人为这次寄的信付给弗朗切斯科 ·德尔 · 内罗15卡利尼。 仆尼科洛 · 马基雅维利，国务秘书</p><p>信件5</p><p>诸位大人钧鉴： 在收到诸位大人于昨天16点写下的来信后，我立即再次求见了潘多尔 福，并与他进行了一番长谈。我以自己认为得体的方式提到了诸位大人信 中的主题。他毫不费力地对其进行了答复。显然，他脑子里所想的，都是 他在回复你们的第一封信时对我说过的话。他再次向我保证说，他是完全 不愿意看到这次行动的。他向你们通风报信，同时还劝说德 · 阿尔维阿诺 收手，这都证明了他说过的话，即他一有机会就会去反对这件事。不仅如 此，据他说，为了探究事情的真相，而且也为了更好地理解这整件事务的 情况，他已经给自己驻罗马的代理人去信，指引后者前去会见枢机主教桑 塔 · 克罗，并查明巴尔托洛梅奥是否是奉西班牙之命而采取行动的。假如 他是在西班牙国王的建议下行动的，那么,与没有这种建议的情况相比， 他就必须采取一条不同的途径。潘多尔福说他今天早上收到了对这一问题 的答复。根据这一答复，桑塔 · 克罗说自己对此一无所知，但相信巴尔托 洛梅奥并没有得到西班牙的许可。不过，为了确保万无一失，潘多尔福还 会写信给孔萨尔沃，看看会收到什么答复。但他相信，孔萨尔沃已经给 德 · 阿尔维阿诺下了命令，要求他彻底放弃自己的企图。因此，潘多尔福 假装自己在谈判方面和战略方面都已经竭尽了全力，但假如他最终被迫要 公开使用暴力的话，他需要诸位大人的同意和支持。可如果没有达成全面 谅解的话，他是无法信赖你们的。因此，他一直在对我说，有必要先敲定 一份协议，然后再去提供更有力的补救方法。在这场事件中，他绝没有一</p><p>第三次出使锡耶纳的潘多尔福·彼得鲁奇</p><p>边息事宁人一边煽风点火，因为他没有煽风点火的手段，同时又在尽力地 息事宁人。但是，由于他怀疑自己没有能力去完成一切必要的事情，所以 才请求与诸位大人进行合作。不过，他希望以明智的方式展开合作，使其 能对双方都有利，而不是仅仅对一方有利。 我尽量向诸位大人逐字逐句地复述潘多尔福的话，以使你们能更好地 判断他的意图，并决定如何行动才最符合我们共和国的利益。我不想浪费 诸位大人的时间，所以没有把我对潘多尔福的所有回复都写进信里。但我 把所有基于自己经验和判断的东西都写下来了。不过，这些东西的用处不 大，因为潘多尔福这个人行事前总是胸有成竹，只要他想就能克服一切。 因此，我对他的诸多回答之一就是，孔萨尔沃与巴尔托洛梅奥的合约在本 月20日到期，所以，我不明白前者怎么能够命令后者停止进军。对此，他 回答道，他曾说过巴尔托洛梅奥与西班牙人的合同只订到20日为止，因为 当他上一次见到巴尔托洛梅奥时，曾经问过后者，考虑到鲁切尔拉约所发 起的谈判，他是否能和法国人或你们签订合同。巴尔托洛梅奥回答说，他 在7月20日以后就可以这么做了。于是，潘多尔福便得出结论说，巴尔托 洛梅奥和西班牙人的合同将在那天到期。但在那之后，他又听说这一合同 的有效期一直会到10月底。这个消息很可能是真的，因为该合同是在10月 生效的，而这种合同一般都是为期一整年。不过，它也可能会包含一项 条款，允许德 · 阿尔维阿诺提前两三个月同其他人签约。潘多尔福还告诉 我，他从罗马听说，教皇正在敦促巴尔托洛梅奥离开教会领地。由于害怕 巴尔托洛梅奥会攻击和劫掠自己在奥尔蒂的部队，教皇从罗马向那里派去 了步兵和骑兵。我又向潘多尔福指出，只要孔萨尔沃和巴尔托洛梅奥之间 不再有联系，后者就无法将皮翁比诺的步兵(或者那里的其他什么兵力) 收为己用。对此，他回答说，我的看法是正确的，但他相信德 · 阿尔维阿 诺会从其他地方获得步兵，而且，正是出于这个原因，巴尔托洛梅奥才去 寻求与詹保罗会面，以便要求后者提供步兵。就像他以前告诉过我的那 样，詹保罗去和巴尔托洛梅奥见了面。他之后曾说詹保罗派了佩波大人去</p><p>政务与外交著作 Legazioni,commissarie,scrittidigoverno</p><p>第三次出使锡耶纳的潘多尔福·彼得鲁奇 会面，但这是不准确的。不过，他不相信詹保罗会去帮助巴尔托洛梅奥或 给他出谋划策。潘多尔福说他已经下令让科尔内略去介入他们的谈判，以 便了解其中的一切情况，而一旦他得到回复，就会来告知我。 在这场对整个事件的漫长讨论与争执后，我对潘多尔福说，他应该明 白别人是能理解所有这些巧妙或低劣的借口的。而这些阴谋让我感到如此 不知所措，以至于我害怕自己回家之前就会被搞得晕头转向了。我曾一度 被告知说，巴尔托洛梅奥正带着西班牙人提供的步兵和资金向前挺进，然 后，又听说他其实既没有士兵也没有钱。先是说孔萨尔沃会命令他按兵不 动，然后，我又听说他会在两三天内动身启程，而这就表明他已经收到了 所需的全部援助。现在，我又被告知说，他开始求詹保罗给他提供步兵 了。前一天我还听说教皇非常倚仗他，第二天又听说教皇对他感到害怕。 我刚刚还听说他和锡耶纳有着极好的关系，却又马上听说他的士兵正在洗 劫锡耶纳。因此，我恳求他向我解释一下这些矛盾。潘多尔福回答说： “我会像腓特烈国王回答我的一个信使的类似问题那样，来回答你的问 题：为了避免陷入错误，我们必须根据每天发生的不同事件来改变我们的 行动，而且必须时时对事物做出判断，因为时间和环境比人类的智慧更有 力量。”他还说，当前的时代受到了德 · 阿尔维阿诺这种人精神的影响， 当他把自己武装起来时，就能够同时激发邻人的希望和恐惧。我随后告诉 他，诸位大人针对曼托瓦和米兰采取了措施，以使其他人不会太指望来自 它们的支持。 潘多尔福没有谈到维泰利家族，因为他还没有收到对他昨天那封信的 回复(他在那封信里稍稍深入地谈论了这件事)。对于我在昨天的信里向 诸位大人所写的那些事情，我目前也无法做出回复。从德 · 阿尔维阿诺的 军营中，还没有传来更多的消息。 敬请诸位大人多多关照。 1505年7月21日，19点，锡耶纳 潘多尔福又向我说起了他的那个科尔托纳人，并提出，假如有什么对</p><p>马基雅维利全集 Opere complete di Niccolo Machiavelli</p><p>第三次出使锡耶纳的潘多尔福·彼得鲁奇 他自己不利的证词，他可以面见诸位大人。 仆尼科洛 · 马基雅维利，国务秘书</p><p>信件6</p><p>诸位大人钧鉴： 在21日的22点，我收到了诸位大人当天所写的上一封信。我注意到诸 位大人谈到了米凯莱 ·迪 ·里奇大人的提议，于是便求见了潘多尔福，并 以我认为得体的方式传达了诸位大人的意思。潘多尔福回答说，他尚未就 此问题与米凯莱谈过。如果后者提出了那项建议的话，肯定是由于他希望 能够缔结协议，而且认为自己的做法大概是最有助于此的。当我问到他的 想法时，他说他必须和他的一些公民对此问题进行商议，但他个人的直觉 是，这对于锡耶纳人民的安全没有丝毫好处。我们讨论了一会儿这件事 情，尽管我认为我清楚地了解了他的情感，但我还是觉得不应该马上给诸 位大人去信，因为我想到，潘多尔福在经过进一步的考虑后，可能会部分 同意那项提议。我没有得到潘多尔福的更多答复，也就没有什么新东西可 以写信告知诸位大人，因为他昨天忙于和锡耶纳市民一起举行隆重的宴请， 以庆祝九人团③的归来。他以此为由，把回复的时间推迟到了今天早上。 于是，我就在合适的时间到了大教堂，并找到了潘多尔福。在他身 边，还有他那里4位显赫的公民。在我入座之后，潘多尔福简短地告诉 我，他将让我和安东尼奥 ·达 · 韦纳弗罗先生待在一起，并由后者把他们 的决定告诉我。于是我就被留下与安东尼奥先生单独相处。他对我说，在 米凯莱大人的提议中，他看不到对锡耶纳人民的安全有什么好处，因为他 注意到，这项提议将他们置于了两种危险之中。首先，出于某些原因，国</p><p>① 九 人 团( Monte dei Nove) , 锡耶纳共和国的最高裁判机构，曾经多次变革。——贝尔泰利编校本注</p><p>王可能会不愿或无法做出决定。其次，就算他做出了决定，他也可能会把 蒙泰普尔恰诺判给诸位大人。这里的人们相信，在你们收复比萨之后，就 算国王把蒙泰普尔恰诺判给你们，你们也会乐于答应把这块地让出去。然 而，只要上述两种结果之一还可能存在，他们就不免会有所疑虑，因此也 就永远不会同意那项提议，除非能首先找到驱散那种不确定性的方法。他 认为，最好的方法就是一开始曾被提议过的那种，因为试图让国王去向锡 耶纳人民做出保证，乃是一件耗费时日的事情，而我们已经没有多少时间 去做好适当的准备工作，以抵御那些想要摧毁托斯卡纳的人了。 与我这里所写下的内容相比，安东尼奥先生的谈话要长得多。为了回 答他，我用尽了我认为得体的话，来为诸位大人的行为加以辩护。他凭借 自己出众的能力，找到了一切证据来说明潘多尔福是多么希望与诸位大人 缔约，以及除了他希望缔约的善意之外，他是如何希望以更大的善意来执 行这项协约的。安东尼奥补充说，协议的签订对你们有巨大的好处，而他 又了解你们的智慧，所以，对于订约过程中遇到的重重阻力，他感到非常 震惊。他无法理解你们为何会犹豫不决。由于他在这件事上说得太过火 了，我忍不住向他指出说，阻力更多的是来自其他人，而不是来自诸位大 人。更具体地说，阻力来自那些想得到不属于自己的分外好处的人。达成 协议的主要障碍并非像某些心怀私欲者所说，是蒙泰普尔恰诺的分离(尽 管那也会涉及到荣誉和利益的损失)。这种说法已经在许多人的心中导致 了不信任，并使他们怀疑说，即使他们让蒙泰普尔恰诺分离出去了，也不 会产生任何作用，因为他们似乎认为有人想用侮辱和暴力使他们臣服。 过去的很多事情都导致他们产生了这样一种印象，我不想逐一重复这些 事，只想提一下同卢卡协议的撕毁、同詹保罗合同的破裂，以及巴尔托洛 梅奥 ·德 · 阿尔维阿诺当前的举动。在这最后一件事上，我们一边被人求 着帮忙，同时却又遭到了恳求者的威胁。我对安东尼奥说，他非常清楚， 伤害产生敌意，而互利带来友谊。试图通过伤害一个人来使他成为自己的 朋友，乃是犯了天大的错误。因此，我对潘多尔福、安东尼奥和其他许多 \u2028第三次出使锡耶纳的潘多尔福·彼得鲁奇</p><p>Opere complete di Niccolo Machiavelli</p><p>第三次出使锡耶纳的潘多尔福·彼得鲁奇 公民都多次说过，如果想顺利签订协议的话，他们就必须去消除自己引发 的这些不信任，而为了做到这一点，对这些不信任的存在负有最大责任的 人，就应该去付出最大的努力。锡耶纳人现在要做的，就是表明他们有备 而来、团结一致，而且唯一的目的就是去抵抗巴尔托洛梅奥。如果他们的 善意能够得到证明，就会迅速培育出友谊，并且肯定会消除一切不信任。 否则的话，由于没有时间去建立这样的友谊，我担心我们会发现整件事务 都会陷于混乱，以至于让每个人都充满恐惧。在很短的时间内，我就曾在 这里见过许多人夏天还开怀大笑，到了冬天就哭天抹泪了。我以前就曾经 说过，现在也想再提醒他一遍，在混乱的局势下，最感到害怕的和最难以 有所收获的，通常都是最虚弱的人。 尽管如此，安东尼奥先生仍然坚持他的看法。他向我讲述了大量的理 由向我表明，如果锡耶纳和佛罗伦萨之间没有签订协议，你们就不可能合 理地希望和指望获取任何利益。正是由于没有签订协议，他们才撕毁了与 卢卡的协定，中止了与詹保罗的合同，并且没有做任何事情来补救当前的 困局。这是因为，除非你们对他们加以保护，否则他们就无法亮剑与其他 人为敌。但是，如果双方之间能够达成协议的话，你们马上就会成为托斯 卡纳的主人了。随后，他重新着重指出了这样做给你们带来的巨大好处， 并数次对我说道： “相信我，尼科洛，向你们谴责潘多尔福的人或许能给 出许多理由，但不会把他们心里的真实想法告诉你们。”我尽了最大努力 去和他争执，但无法从他那里获得更多的东西。 潘多尔福告诉我，他没有从巴尔托洛梅奥的军营里收到消息。由于科 尔内略没有给他写信，他猜想，军队并未像之前来信所说的那样于昨天开 拔。他承诺，一旦听说任何消息，就会马上让我知道。但这纯粹是他的一 面之词，因为我无法从其他的来源获得关于此事的信息。 1505年7月23日，锡耶纳 仆尼科洛 · 马基雅维利，国务秘书 请诸位大人付给在17点传送此信的弗朗切斯科 ·德尔 · 内罗15卡利尼。</p><p>Legazioni,commissarie,scritti di governo</p><p>第三次出使锡耶纳的潘多尔福·彼得鲁奇 信件7</p><p>诸位大人钧鉴： 在上一封即我昨天17点的那封信里，我向诸位大人报告了潘多尔 福对21日来信中米凯莱 · 里奇先生所作提议的回复，以及随后安东尼 奥 ·达 · 韦纳弗罗先生以他的名义所作的回复。你们可以从我的来信中看 到，我们必须放弃为达成协议而做的谈判，或者以我在给诸位大人的第一 封信中建议的方式签署协议。在昨晚约24点时，潘多尔福召见了我并通知 说，他收到了22日分别从罗马和军营寄来的信。他向我读了罗马的来信。 那封信是用密码写成的，但已经被用惯常的方式破译了。他派往该城的特 使告诉他，枢机主教桑塔 · 克罗已经从那不勒斯收到了回信，其内容涉及 他向孔萨尔沃提的问题，即巴尔托洛梅奥的举动是否得到了他的授意。回 信说，他的举动违背了孔萨尔沃的愿望，后者已经派了一位特使前去巴尔 托洛梅奥那里，命令他不要干预托斯卡纳或比萨的事务。梅迪奇枢机主教 也通过他安插在孔萨尔沃身边的人获得了同样的信息。对于来自军营的那 封信，潘多尔福只给我读了涉及维泰利家族的那一部分。信中说，朱利奥 大人和他们的兄弟乔瓦尼都给出了答复。两人都完全愿意服从潘多尔福 的意志，同时还愿意去做一切对他最为有利的事情，并以最热切真诚的词 语，表达了他们愿意去做一切他所喜欢的事情的急切愿望。潘多尔福接着 对我说，这封信告诉他，军队尚未像最近所说的那样从塞尔瓦启程，但他 们将于今天早上动身，经由马雷马地区的道路，前往卡波迪蒙山丘。詹保 罗已经见过了巴尔托洛梅奥。后者请求他的支持，但他既没有答应也没有 拒绝。 我向潘多尔福传达这一信息的做法表示了谢意，但略过了涉及维泰利 家族的那一部分，因为对于我信里所写的相关内容，诸位大人还没有给予 答复。而且，在我看来，这样做也是最好的选择，因为除了他所读的信中 内容外，潘多尔福也没有对此多说。我告诉他，我对詹保罗的行为感到不</p><p>马基雅维利全集 Opere complete di Niccolò Machiavelli</p><p>第三次出使锡耶纳的潘多尔福·彼得鲁奇 快。他本应断然拒绝巴尔托洛梅奥。潘多尔福也应尽力使詹保罗拒绝支持 巴尔托洛梅奥，而且我相信他很容易就能做到这一点，因为詹保罗完全信 任他，并且实际上还在拿着他的钱。他回答说，他希望与詹保罗面谈此 事，所以已经下令他掉头朝佩鲁贾方向前进，以尽量接近本地，从而使他 可以前去会见詹保罗，或者干脆就来到锡耶纳。我问他是否相信巴尔托洛 梅奥，以及，假设来自罗马的消息是真实的，他是否认为后者会不顾孔萨 尔沃的命令而继续前进。他回答说，他无法做出判断，但德 · 阿尔维阿诺 的理智应该会约束他，不让他去违背孔萨尔沃的意志，因为他在10月前都 要为后者效力。对于他要效力到10月这一点，潘多尔福还不能肯定，但在 他看来，如果德 · 阿尔维阿诺神父去那不勒斯真的是为了钱(就像给他的 信里所说的那样),则这点就可以确定了。然而，就算理智告诉德 · 阿尔 维阿诺要停下来，他也可能出于绝望而继续挺进。为此，潘多尔福建议诸 位大人做好适当的准备。虽说在出于绝望而行动的人里，有四分之三都下 场不妙，但最好还是不要让巴尔托洛梅奥受到绝望的驱使，因为每当我们 去做一件事时，总难免会惹起一千件其他的事情，何况事情的走向又非常 的不确定。随后，他又再次强调说，诸位大人应该踩灭这可能导致大火的 第一粒火星。他还说，如果你们能够统一托斯卡纳的话，就能成为它的主 人。统一后的托斯卡纳将会把力量集结起来，使其能抵御任何试图侵犯它 的人，并受到所有人的尊重。如果你们怀疑奥尔西尼家族的话，可以把 维泰利家族和巴廖尼从他们那里策反过来。这是很容易做到的，因为他们 会感到，比起奥尔西尼家族的保护，统一的托斯卡纳会让他们更加安全。 事实上，在他看来，这件事太容易了，它所能提供的安全也太诱人了，所 以，假如事情没有成功的话，唯一的原因就是，上帝希望意大利的这个美 丽省份遭受劫难。他在评论过程中曾说到，可以用另一种手段降服巴尔托 洛梅奥，使其变得无害。这种手段就使他在比萨人眼中变得可疑，而我们 有上千种方法可以做到这一点。潘多尔福不想深入谈论具体的方法，但在 其他事情上说了许多，而我也都一一做了回答。不过，我没有把这些话都</p><p>政务与外交著作 Legazioni,commissarie,scritti digoverno</p><p>写下来,以免徒劳无益地让诸位大人感到厌倦。 我会把此信送到驿站,使其由第一位离开的信差带走。我本来想通过 专门的信使寄走这封信,但那样的话我手头就只剩1个银币了,而我在旅 馆这边还欠着债。我恳请诸位大人要么把我召回(我是非常希望你们这么 做的),要么给我提供所需的金钱。 敬请诸位大人多多关照。 锡耶纳,1505年7月24日 仆尼科洛 · 马基雅维利,国务秘书 \u2028第三次出使锡耶纳的潘多尔福·彼得鲁奇</p><p>第二次派往比萨战场①</p><p>1505年8月</p><p>上 一 次任务的按语里提到，佛罗伦萨人打败了巴尔托洛梅 奥 · 德 · 阿尔维阿诺。在这之后，他们认为应该利用那次胜利所创 造的激情，去尝试征服比萨。为此，他们做了大量的准备工作，并 向军营专员安东尼奥 · 贾科米尼下达了命令，要求他立即挥军直抵 比萨城下。马基雅维利被派往军营，去和贾科米尼协调一切必要的 准备工作与供给。然而，由于军队的怯懦，这次行动最终失败了。 下列信件的内容包括佛罗伦萨共和国所采取的措施和所下达的命 令。我们将它们也编辑进了马基雅维利的出使文件之中。</p><p>信件1</p>',76)])])}const h=i(c,[["render",r]]);export{v as __pageData,h as default};
